-- CREATE PROMOS TABLE
CREATE TABLE "public"."promos" (
    "id" bigint GENERATED BY DEFAULT AS IDENTITY PRIMARY KEY,
    "code" text UNIQUE NOT NULL,
    "discount_type" text NOT NULL,
    "discount_value" numeric(10,2) NOT NULL,
    "usage_count" integer DEFAULT 0,
    "status" text DEFAULT 'Active',
    "created_at" timestamp with time zone DEFAULT timezone('utc'::text, now()) NOT NULL
);

-- CREATE REVIEWS TABLE
CREATE TABLE "public"."reviews" (
    "id" bigint GENERATED BY DEFAULT AS IDENTITY PRIMARY KEY,
    "customer_name" text NOT NULL,
    "product_name" text NOT NULL,
    "rating" integer NOT NULL,
    "comment" text NOT NULL,
    "status" text DEFAULT 'Pending',
    "created_at" timestamp with time zone DEFAULT timezone('utc'::text, now()) NOT NULL
);

-- SET UP ROW LEVEL SECURITY
ALTER TABLE "public"."promos" ENABLE ROW LEVEL SECURITY;
ALTER TABLE "public"."reviews" ENABLE ROW LEVEL SECURITY;

-- CREATE POLICIES TO ALLOW ALL OPERATIONS FOR THIS DEMONSTRATION
CREATE POLICY "Enable all operations for all users on promos" ON "public"."promos" FOR ALL USING (true) WITH CHECK (true);
CREATE POLICY "Enable all operations for all users on reviews" ON "public"."reviews" FOR ALL USING (true) WITH CHECK (true);

