-- ADD MISSING COLUMNS TO ORDERS TABLE (run in Supabase SQL Editor if not already present)
ALTER TABLE "public"."orders" ADD COLUMN IF NOT EXISTS "phone" text;
ALTER TABLE "public"."orders" ADD COLUMN IF NOT EXISTS "shipping_address" text;
ALTER TABLE "public"."orders" ADD COLUMN IF NOT EXISTS "order_items" jsonb;

-- DATA FIX: Link existing orders to customers by email where customer_id is missing
UPDATE "public"."orders" o
SET "customer_id" = c."id"
FROM "public"."customers" c
WHERE o."email" = c."email" AND o."customer_id" IS NULL;

-- ENSURE IMAGES ARRAY COLUMN EXISTS
ALTER TABLE "public"."products" ADD COLUMN IF NOT EXISTS "images" text[] DEFAULT '{}';

